package com.example.demo.controller;
import com.example.demo.exception.ApiException; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import java.io.IOException; import java.nio.file.*; import java.util.*;
@RestController @RequestMapping("/api/uploads")
public class UploadController { private final SalesService service; public UploadController(SalesService service){this.service=service;} @PostMapping(value="/images",consumes="multipart/form-data") public Map<String,String> upload(@RequestHeader("Authorization")String auth,@RequestParam("file")MultipartFile file){service.adminOnly(auth);if(file.isEmpty()||file.getContentType()==null||!file.getContentType().startsWith("image/"))throw new ApiException(HttpStatus.BAD_REQUEST,"Vui lòng chọn tệp ảnh hợp lệ");try{Path folder=Paths.get("uploads");Files.createDirectories(folder);String ext=Optional.ofNullable(file.getOriginalFilename()).filter(n->n.contains(".")).map(n->n.substring(n.lastIndexOf('.'))).orElse(".jpg");String name=UUID.randomUUID()+ext;Files.copy(file.getInputStream(),folder.resolve(name),StandardCopyOption.REPLACE_EXISTING);return Map.of("imageUrl","/uploads/"+name);}catch(IOException e){throw new ApiException(HttpStatus.INTERNAL_SERVER_ERROR,"Không thể lưu ảnh");}} }
